import {
  SignaturePad as SignaturePadPrimitive,
  useSignaturePad,
  useSignaturePadContext,
} from '@ark-ui/react/signature-pad';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef, ReactElement, ReactNode } from 'react';
import { Children, cloneElement, forwardRef } from 'react';
import { RotateCcwIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import { CloseButton } from '../close-button';
import styles from './SignaturePad.module.css';

const SignaturePadRoot = forwardRef<
  ComponentRef<typeof SignaturePadPrimitive.Root>,
  ComponentProps<typeof SignaturePadPrimitive.Root> & SignaturePadFormProps
>(function SignaturePadRoot({ asChild, children, className, getFormValue, ...props }, ref) {
  return (
    <SignaturePadPrimitive.Root
      ref={ref}
      data-slot="signature-pad-root"
      className={clsx(styles.root, normalizeClassName(className))}
      asChild={asChild}
      {...props}
    >
      {withHiddenInput(children, asChild, getFormValue)}
    </SignaturePadPrimitive.Root>
  );
});

const SignaturePadRootProvider = forwardRef<
  ComponentRef<typeof SignaturePadPrimitive.RootProvider>,
  ComponentProps<typeof SignaturePadPrimitive.RootProvider> & SignaturePadFormProps
>(function SignaturePadRootProvider({ asChild, children, className, getFormValue, ...props }, ref) {
  return (
    <SignaturePadPrimitive.RootProvider
      ref={ref}
      data-slot="signature-pad-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      asChild={asChild}
      {...props}
    >
      {withHiddenInput(children, asChild, getFormValue)}
    </SignaturePadPrimitive.RootProvider>
  );
});

const SignaturePadLabel = forwardRef<
  ComponentRef<typeof SignaturePadPrimitive.Label>,
  ComponentProps<typeof SignaturePadPrimitive.Label>
>(function SignaturePadLabel({ className, ...props }, ref) {
  return (
    <SignaturePadPrimitive.Label
      ref={ref}
      data-slot="signature-pad-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const SignaturePadControl = forwardRef<
  ComponentRef<typeof SignaturePadPrimitive.Control>,
  ComponentProps<typeof SignaturePadPrimitive.Control>
>(function SignaturePadControl({ className, ...props }, ref) {
  return (
    <SignaturePadPrimitive.Control
      ref={ref}
      data-slot="signature-pad-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const SignaturePadSegment = forwardRef<
  ComponentRef<typeof SignaturePadPrimitive.Segment>,
  ComponentProps<typeof SignaturePadPrimitive.Segment>
>(function SignaturePadSegment({ className, ...props }, ref) {
  return (
    <SignaturePadPrimitive.Segment
      ref={ref}
      data-slot="signature-pad-segment"
      className={clsx(styles.segment, normalizeClassName(className))}
      {...props}
    />
  );
});

const SignaturePadGuide = forwardRef<
  ComponentRef<typeof SignaturePadPrimitive.Guide>,
  ComponentProps<typeof SignaturePadPrimitive.Guide>
>(function SignaturePadGuide({ className, ...props }, ref) {
  return (
    <SignaturePadPrimitive.Guide
      ref={ref}
      data-slot="signature-pad-guide"
      className={clsx(styles.guide, normalizeClassName(className))}
      {...props}
    />
  );
});

const SignaturePadClearTrigger = forwardRef<
  ComponentRef<typeof SignaturePadPrimitive.ClearTrigger>,
  ComponentProps<typeof SignaturePadPrimitive.ClearTrigger>
>(function SignaturePadClearTrigger(
  {
    asChild,
    className,
    children,
    'aria-label': ariaLabel,
    'aria-labelledby': ariaLabelledBy,
    ...props
  },
  ref,
) {
  const triggerClassName = clsx(styles.clearTrigger, normalizeClassName(className));

  if (asChild) {
    return (
      <SignaturePadPrimitive.ClearTrigger
        ref={ref}
        asChild
        data-slot="signature-pad-clear-trigger"
        className={triggerClassName}
        aria-label={ariaLabel}
        aria-labelledby={ariaLabelledBy}
        {...props}
      >
        {children}
      </SignaturePadPrimitive.ClearTrigger>
    );
  }

  return (
    <SignaturePadPrimitive.ClearTrigger
      ref={ref}
      asChild
      data-slot="signature-pad-clear-trigger"
      className={triggerClassName}
      {...props}
    >
      <CloseButton.Root aria-label={ariaLabel} aria-labelledby={ariaLabelledBy}>
        {children ?? <RotateCcwIcon aria-hidden="true" />}
      </CloseButton.Root>
    </SignaturePadPrimitive.ClearTrigger>
  );
});

type SignaturePadFormProps = {
  getFormValue?: (paths: string[]) => string;
};

function withHiddenInput(
  children: ReactNode,
  asChild: boolean | undefined,
  getFormValue: SignaturePadFormProps['getFormValue'],
) {
  const hiddenInput = <SignaturePadFormInput getFormValue={getFormValue} />;

  if (!asChild) {
    return (
      <>
        {children}
        {hiddenInput}
      </>
    );
  }

  const child = Children.only(children) as ReactElement<{ children?: ReactNode }>;

  return cloneElement(child, {}, child.props.children, hiddenInput);
}

function SignaturePadFormInput({ getFormValue }: SignaturePadFormProps) {
  const signaturePad = useSignaturePadContext();

  return (
    <SignaturePadPrimitive.HiddenInput
      data-slot="signature-pad-hidden-input"
      value={getFormValue?.(signaturePad.paths) ?? signaturePad.paths.join(' ')}
    />
  );
}

function SignaturePadCanvas({ className }: { className?: string }) {
  return (
    <SignaturePadControl className={className}>
      <SignaturePadSegment />
      <SignaturePadClearTrigger>
        <RotateCcwIcon aria-hidden="true" />
      </SignaturePadClearTrigger>
      <SignaturePadGuide />
    </SignaturePadControl>
  );
}

const SignaturePad = Object.assign(SignaturePadRoot, {
  Root: SignaturePadRoot,
  RootProvider: SignaturePadRootProvider,
  Label: SignaturePadLabel,
  Control: SignaturePadControl,
  Canvas: SignaturePadCanvas,
  Segment: SignaturePadSegment,
  Guide: SignaturePadGuide,
  ClearTrigger: SignaturePadClearTrigger,
});

export { SignaturePad, useSignaturePad, useSignaturePadContext };

@layer moduix.components {
  .root {
    box-sizing: border-box;
    display: inline-flex;
    flex-direction: column;
    gap: var(--moduix-signature-pad-gap, var(--moduix-spacing-2));
    width: var(--moduix-signature-pad-width, 17.5rem);
    max-width: var(--moduix-signature-pad-max-width, 100%);
    color: var(--moduix-signature-pad-color, var(--moduix-color-foreground));

    &[data-disabled] {
      opacity: var(--moduix-signature-pad-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .label {
    color: var(--moduix-signature-pad-label-color, var(--moduix-color-foreground));
    font-size: var(--moduix-signature-pad-label-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-signature-pad-label-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-signature-pad-label-line-height, var(--moduix-line-height-text-sm));
    user-select: none;

    &[data-disabled] {
      opacity: var(--moduix-signature-pad-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .control {
    box-sizing: border-box;
    width: var(--moduix-signature-pad-control-width, 100%);
    min-width: var(--moduix-signature-pad-control-min-width, 0);
    height: var(--moduix-signature-pad-control-height, var(--moduix-signature-pad-height, 10rem));
    min-height: var(--moduix-signature-pad-control-min-height, 10rem);
    border: var(--moduix-signature-pad-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-signature-pad-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-signature-pad-radius, var(--moduix-radius-md));
    background-color: var(--moduix-signature-pad-bg, var(--moduix-color-background));
    color: var(--moduix-signature-pad-stroke-color, var(--moduix-color-foreground));
    box-shadow: var(--moduix-signature-pad-shadow, var(--moduix-shadow-sm));
    outline: none;
    overflow: hidden;
    transition:
      border-color var(--moduix-signature-pad-transition, var(--moduix-transition-default)),
      box-shadow var(--moduix-signature-pad-transition, var(--moduix-transition-default)),
      opacity var(--moduix-signature-pad-transition, var(--moduix-transition-default));

    &[data-disabled] {
      cursor: not-allowed;
    }

    &:focus-visible {
      border-color: var(--moduix-signature-pad-focus-border-color, var(--moduix-color-ring));
      box-shadow: 0 0 0
        var(
          --moduix-signature-pad-focus-ring-width,
          var(--moduix-focus-ring-width, var(--moduix-border-width-md))
        )
        var(--moduix-signature-pad-focus-ring-color, var(--moduix-color-ring));
    }
  }

  .segment {
    fill: var(--moduix-signature-pad-stroke-color, currentColor);
  }

  .guide {
    position: absolute;
    inset-inline-end: var(--moduix-signature-pad-guide-inset-x, var(--moduix-spacing-6));
    bottom: var(--moduix-signature-pad-guide-bottom, var(--moduix-spacing-8));
    inset-inline-start: var(--moduix-signature-pad-guide-inset-x, var(--moduix-spacing-6));
    border-bottom: var(--moduix-signature-pad-guide-border-width, var(--moduix-border-width-sm))
      dashed var(--moduix-signature-pad-guide-color, var(--moduix-color-border));
    pointer-events: none;

    &[data-disabled] {
      opacity: var(--moduix-signature-pad-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .clearTrigger {
    position: absolute;
    top: var(--moduix-signature-pad-clear-trigger-offset, var(--moduix-spacing-2));
    inset-inline-end: var(--moduix-signature-pad-clear-trigger-offset, var(--moduix-spacing-2));
    border: var(--moduix-signature-pad-clear-trigger-border-width, 0) solid
      var(--moduix-signature-pad-clear-trigger-border-color, transparent);
    --moduix-close-button-size: var(
      --moduix-signature-pad-clear-trigger-size,
      var(--moduix-size-md)
    );
    --moduix-close-button-radius: var(
      --moduix-signature-pad-clear-trigger-radius,
      var(--moduix-radius-sm)
    );
    --moduix-close-button-bg: var(--moduix-signature-pad-clear-trigger-bg, transparent);
    --moduix-close-button-bg-hover: var(
      --moduix-signature-pad-clear-trigger-bg-hover,
      var(--moduix-color-accent)
    );
    --moduix-close-button-color: var(
      --moduix-signature-pad-clear-trigger-color,
      var(--moduix-color-muted-foreground)
    );
    --moduix-close-button-color-hover: var(
      --moduix-signature-pad-clear-trigger-color-hover,
      var(--moduix-color-foreground)
    );
    --moduix-close-button-icon-size: var(
      --moduix-signature-pad-clear-trigger-icon-size,
      var(--moduix-spacing-4)
    );
    --moduix-close-button-transition: var(
      --moduix-signature-pad-transition,
      var(--moduix-transition-default)
    );
    --moduix-close-button-focus-ring-width: var(
      --moduix-signature-pad-clear-trigger-focus-ring-width,
      var(--moduix-focus-ring-width, var(--moduix-border-width-md))
    );
    --moduix-close-button-focus-ring-color: var(
      --moduix-signature-pad-clear-trigger-focus-ring-color,
      var(--moduix-color-ring)
    );
    --moduix-close-button-focus-ring-offset: var(
      --moduix-signature-pad-clear-trigger-focus-ring-offset,
      var(--moduix-spacing-1)
    );
    --moduix-close-button-disabled-opacity: var(
      --moduix-signature-pad-disabled-opacity,
      var(--moduix-opacity-disabled)
    );
  }
}
